Actionscript.script:
// ========== 基础属性 ==========
方向 = 方向 === "左" ? "左" : "右";
if (方向 === "左") this._xscale = -100;

switch(this._name) {
    case "雕像0":
        this.召唤物名 = "敌人-诺亚克隆兽";
        this.召唤物参数 = {等级:30, 名字:"克隆兽", 是否为敌人:true, 身高:230, 性别:"男", 产生源:this._name};
        break;
    case "雕像1":
        this.召唤物名 = "敌人-普通爆炸僵尸";
        this.召唤物参数 = {等级:30, 名字:"爆炸僵尸", 是否为敌人:true, 身高:200, 性别:"男", 产生源:this._name};
        break;
    case "雕像2":
        this.召唤物名 = "敌人-闪6特工";
        this.召唤物参数 = {等级:30, 名字:"克隆人", 是否为敌人:true, 身高:190, 性别:"女", 产生源:this._name};
        break;
}
this.召唤物计数 = 0;

Z轴坐标 = this._y;
hp = hp满血值 = 45000;
防御力 = 1;
躲闪率 = 100;
回血间隔帧 = 0;
var 已激活 = false;
var 最大复活时间 = 25000;   // 毫秒
var 复活时间 = 4000;        // 首次复活时间
var 死亡次数 = 0;
var 正在死亡 = false;

_root.敌人函数.初始化单位(this);
gotoAndStop("正常");
this._visible = false;

// ========== 由中枢调用的激活/隐藏接口 ==========
function 激活() {
    已激活 = true;
    正在死亡 = false;
    躲闪率 = 0;                 // 可被攻击
    hp = hp满血值;
    this._visible = true;
    gotoAndStop("正常");
    _root.帧计时器.移除任务(this, "复活计时");
}

function 强制隐藏() {
    已激活 = false;
    this._visible = false;
    _root.帧计时器.移除任务(this, "复活计时");
    stop();
}

// ========== 重写死亡检测（不注销，只进入死亡/复活流程） ==========
function 死亡检测() {
    if (_parent.hp <= 0 && !正在死亡 && 已激活) {
        正在死亡 = true;

        // 处理经验值等（如需要）
        if (_parent.已加经验值 != true && _parent.是否为敌人 == true) {
            _root.敌人死亡计数++;
            _parent.计算经验值();
        }

        gotoAndStop("结束");
        // 启动复活
        复活计时();
    }
}

// ========== 复活计时（延迟后恢复HP） ==========
function 复活计时() {
    if (!已激活) return;

    // 召唤小怪（沿用原逻辑）
    var 游戏世界 = _root.gameworld;
    var 敌人实例名 = this._name + 召唤物名 + 召唤物计数;
    var 召唤物 = _root.加载游戏世界人物(召唤物名, 敌人实例名, 游戏世界.getNextHighestDepth(), 召唤物参数);
    召唤物._x = 游戏世界.door1._x;
    召唤物._y = 游戏世界.door1._y;
    游戏世界.door1.gotoAndPlay("开门");
    召唤物计数++;

    var 自机 = this;
    _root.帧计时器.添加或更新任务(this, "复活计时", function() {
        if (自机.已激活 && 自机.正在死亡) {
            // 复活
            自机.hp = 自机.hp满血值;
            自机.gotoAndStop("正常");
            自机.正在死亡 = false;
            死亡次数++;
            复活时间 = Math.min(最大复活时间, 复活时间 + 2000 * 死亡次数);
        }
    }, 复活时间);
}

// ========== 状态改变回调（兼容原有） ==========
function 状态改变(状态) {
    if (hp == 0) {
        if (已激活) {
            死亡检测();
        } else {
            this._visible = false;
        }
    }
}

// ========== 动画完毕（保证返回正常帧） ==========
function 动画完毕() {
    if (hp > 0) {
        gotoAndStop("正常");
    } else {
        gotoAndStop("结束");
        if (this.man) this.man.gotoAndPlay(1);
    }
}
